import java.io.*;
import java.nio.file.*;
import java.util.*;

public class DiskCache {
    private final Path cacheDir;

    public DiskCache(String directory) throws IOException {
        this.cacheDir = Paths.get(directory);
        if (!Files.exists(cacheDir)) {
            Files.createDirectories(cacheDir);
        }
    }

    public void put(String key, Object value) throws IOException {
        Path file = cacheDir.resolve(key);
        try (ObjectOutputStream oos = new ObjectOutputStream(Files.newOutputStream(file))) {
            oos.writeObject(value);
        }
    }

    public Object get(String key) throws IOException, ClassNotFoundException {
        Path file = cacheDir.resolve(key);
        if (!Files.exists(file)) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(Files.newInputStream(file))) {
            return ois.readObject();
        }
    }

    public void remove(String key) throws IOException {
        Files.deleteIfExists(cacheDir.resolve(key));
    }

    public static void main(String[] args) {
        try {
            DiskCache cache = new DiskCache("cache");

            // Example object
            UserPreferences userPrefs = new UserPreferences("dark", "large");
            SessionData session = new SessionData("user123", 30);

            // Put objects into the cache
            cache.put("userPrefs", userPrefs);
            cache.put("session", session);

            // Retrieve objects from the cache
            UserPreferences cachedUserPrefs = (UserPreferences) cache.get("userPrefs");
            SessionData cachedSession = (SessionData) cache.get("session");

            System.out.println("Cached User Preferences: " + cachedUserPrefs);
            System.out.println("Cached Session Data: " + cachedSession);

            // Remove an object from the cache
            cache.remove("userPrefs");

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

